import { FormInputGroup, FormSelectGroup } from "Components/Global";
import { useFormContext }                  from "react-hook-form";

const Coordinates = ({
	delegations : {
		line,
		checked,
		longOrLatOptions,
		validateMintAndSec,
		validateMaxDegreeVal,
		hanldeParseDMSHToDecimals,
		handleParseDecimalsToDMSH,
	},
}) => {

	const hookForm = useFormContext();

	const { register, formState } = hookForm;

	return (
		<div className="row">
			{
				checked.degrees ?
					(
						<>
							<FormInputGroup
								key={`${line}_dmsh.degree`}
								className="col-md-3"
								bsSize="sm"
								max="90"
								type="number"
								label="Grados:"
								name={`${line}_dmsh.degree`}
								register={register}
								errors={formState.errors}
								options={{
									required : false,
									onChange : hanldeParseDMSHToDecimals(`${line}_dmsh.degree`),
									max      : validateMaxDegreeVal(),
								}}
							/>
							<FormInputGroup
								className="col-md-3"
								bsSize="sm"
								type="number"
								label="Minutos:"
								name={`${line}_dmsh.minutes`}
								register={register}
								errors={formState.errors}
								options={{
									required : false,
									onChange : hanldeParseDMSHToDecimals(`${line}_dmsh.minutes`),
									...validateMintAndSec(),
								}}
							/>
							<FormInputGroup
								className="col-md-3"
								bsSize="sm"
								type="number"
								label="Segundos:"
								name={`${line}_dmsh.seconds`}
								register={register}
								errors={formState.errors}
								options={{
									required : false,
									onChange : hanldeParseDMSHToDecimals(`${line}_dmsh.seconds`),
									...validateMintAndSec(),
								}}
							/>
							<FormSelectGroup
								className="col-md-3"
								size="sm"
								label="Dirección:"
								name={`${line}_dmsh.hemisphere`}
								options={longOrLatOptions}
								hookForm={hookForm}
								rules={{
									required : false,
									onChange : hanldeParseDMSHToDecimals(`${line}_dmsh.hemisphere`),
									...validateMintAndSec(),
								}}
							/>
						</>
					)
					:
					(
						<FormInputGroup
							key={`general_information.${line}`}
							className="col-md-12"
							bsSize="sm"
							type="number"
							label="Longitud:"
							name={`general_information.${line}`}
							register={register}
							errors={formState.errors}
							options={{ required : false, onChange : handleParseDecimalsToDMSH }}
						/>
					)
			}

		</div>
	);
};

export default Coordinates;
