import { Menu as MenuI }                                      from "react-feather";
import { Link, Prompt, useParams }                            from "react-router-dom";
import { Card, Collapse, Button, Breadcrumb, BreadcrumbItem } from "reactstrap";

//Our Components
import Menu from "../Menu";
import "./HeaderPage.scss";


const HeaderPage = ({
	delegations : {
		isDirty,
		isOpenMenu,
		toggleMenu,
		isSubmitingData,
		getCurrentSection,
		handleSaveBtnClick,
	},
}) => {
	const { id } = useParams();
	return (
		<div id="HeaderPage">
			<Prompt
				when={isDirty}
				message="¿Estás seguro que quieres salir sin guardar los cambios?"
			/>
			<div className="row p-1 gy-1">
				<div className="col-md-8">
					<div className="d-flex align-items-center">
						<Button.Ripple className="btn-icon " color="primary" onClick={toggleMenu}>
							<MenuI size={15} />
						</Button.Ripple>
						<Breadcrumb className="mx-1">
							<BreadcrumbItem>
								<Link to="/app/appraise/records"> Avalúos </Link>
							</BreadcrumbItem>
							<BreadcrumbItem onClick={toggleMenu} className="pointer-cursor">
								<span> Clave Sofia({id}) </span>
							</BreadcrumbItem>
							<BreadcrumbItem active>
								<span> {getCurrentSection()} </span>
							</BreadcrumbItem>
						</Breadcrumb>
					</div>
				</div>
				<Button.Ripple
					color="primary"
					className="col-md-4"
					onClick={handleSaveBtnClick}
					disabled={!isDirty || isSubmitingData}
				>
					Guardar e ir a la siguiente página
				</Button.Ripple>
			</div>
			<Collapse isOpen={isOpenMenu}>
				<Card className="mb-2">
					<Menu id={id} />
				</Card>
			</Collapse>
		</div>
	);
};

export default HeaderPage;
