import { useState }       from "react";
import { useFormContext } from "react-hook-form";

//Our Imports
import { CheckboxInpt, FormInputGroup } from "Components/Global";
import { geoOptions }                   from "Resources/data/GeneralInformationForm";
import Coordinates                      from "../Coordinates";

const { latDirectionOptions, longDirectionOptions } = geoOptions;

const Georeference = () => {

	const hookForm = useFormContext();

	const [checked, setChecked] = useState({ "decimal" : true });

	return (
		<>
			<h4 className="mb-1">Información de Georeferencia</h4>
			<p>
				Nota: La georreferencias deben tener <b>7 decimales</b>. Los formatos automáticos de sofía usarán siempre 7 decimales. En caso de captura manual,
				deben completarse los decimales, siendo el último digito alguno diferente de cero. En caso que el septimo decimal sea 0 se recomienda cambiar por 1.
			</p>
			<div className="group mb-1">
				<CheckboxInpt
					label="Decimales"
					value={checked.decimal}
					checkValue={checked.decimal}
					onChange={()=> setChecked({ "decimal" : true,  "degrees" : false })}
				/>
				<CheckboxInpt
					label="Grados"
					value={checked.degrees}
					checkValue={checked.degrees}
					onChange={()=> setChecked({ "degrees" : true, "decimal" : false })}
				/>
			</div>
			<Coordinates line="long" checked={checked} longOrLatOptions={longDirectionOptions} />
			<Coordinates line="lat" checked={checked} longOrLatOptions={latDirectionOptions} />
			<FormInputGroup
				bsSize="sm"
				type="number"
				label="Altitud:"
				name="general_information.alt"
				register={hookForm.register}
				errors={hookForm.formState.errors}
				options={{ required : false }}
			/>
		</>
	);
};


export default Georeference;
