import { Card, CardBody } from "reactstrap";
import { Info }           from "react-feather";
import { useFormContext } from "react-hook-form";

import { FormInputGroup } from "Components/Global";

const ApplicantForm = () => {

	const { register, formState } = useFormContext();

	return (
		<Card className="mt-1">
			<div className="d-flex align-items-center px-1 pt-1">
				<Info size={16} />
				<p className="mx-1">DATOS DEL SOLICITANTE</p>
			</div>
			<hr />
			<CardBody>
				<div className="row mt-2">
					<FormInputGroup
						bsSize="sm"
						name="applicant.paternal_last_name"
						className="col-md-4"
						label="Apellido Paterno"
						register={register}
						errors={formState.errors}
					/>
					<FormInputGroup
						bsSize="sm"
						name="applicant.maternal_last_name"
						className="col-md-4"
						label="Apellido Materno"
						register={register}
						errors={formState.errors}
					/>
					<FormInputGroup
						bsSize="sm"
						name="applicant.name"
						className="col-md-4"
						label="Nombre(s)"
						register={register}
						errors={formState.errors}
					/>
				</div>
			</CardBody>
		</Card>
	);
};

export default ApplicantForm;
